#!/usr/bin/env python
"""
Bootstrap: Multi-Physics Pareto Optimizer (Phase 3)
REQUIRES: colloidal_thermal.py (Phase 1) + colloidal_acoustic.py (Phase 2)
OPTIONAL: optical/* (miepython) for color prediction; falls back to analytical
Run: python bootstrap_multiphysics_pareto.py
"""
import base64, os, sys

if os.path.exists("core/universal_schema.py"): root = "."
elif os.path.exists("../core/universal_schema.py"): root = ".."
else: print("ERROR: Run from MABE root or one dir below."); sys.exit(1)

deps = ["core/colloidal_thermal.py", "core/colloidal_acoustic.py"]
for d in deps:
    if not os.path.exists(os.path.join(root, d)):
        print(f"ERROR: {d} not found. Run prior multi-physics bootstraps first.")
        sys.exit(1)

_p = os.path.join(root, "core/multiphysics_pareto.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

_p = os.path.join(root, "tests/test_multiphysics_pareto.py")
os.makedirs(os.path.dirname(_p), exist_ok=True)
with open(_p, "w", encoding="utf-8") as f:
    f.write(base64.b64decode("").decode("utf-8"))
print(f"  Wrote {_p}")

print("Done. Run: python -m pytest tests/test_multiphysics_pareto.py -v")